from decimal import Decimal, ROUND_HALF_UP
from typing import Any, Dict, List, Optional


def process_payment(user: Dict[str, Any], cart_items: List[Dict[str, Any]], payment_details: Dict[str, Any]) -> Dict[str, Any]:
    role = str(user.get("role", "basic")).strip().lower()
    discount_map = {
        "basic": Decimal("0.00"),
        "premium": Decimal("0.15"),
        "enterprise": Decimal("0.30"),
    }

    if role not in discount_map:
        raise ValueError(f"Invalid user role: {role}")

    if not isinstance(cart_items, list) or not cart_items:
        raise ValueError("cart_items must be a non-empty list")

    subtotal = Decimal("0.00")
    normalized_items = []

    for item in cart_items:
        if not isinstance(item, dict):
            raise ValueError("Each cart item must be a dictionary")

        name = item.get("name", "item")
        quantity = item.get("quantity", 1)
        price = item.get("price")

        if price is None:
            raise ValueError(f"Missing price for cart item: {name}")

        quantity = int(quantity)
        if quantity <= 0:
            raise ValueError(f"Invalid quantity for cart item: {name}")

        price_dec = Decimal(str(price))
        if price_dec < 0:
            raise ValueError(f"Invalid price for cart item: {name}")

        line_total = (price_dec * quantity).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        subtotal += line_total

        normalized_items.append({
            "name": name,
            "quantity": quantity,
            "unit_price": price_dec.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP),
            "line_total": line_total,
        })

    subtotal = subtotal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    discount_rate = discount_map[role]
    discount_amount = (subtotal * discount_rate).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    total = (subtotal - discount_amount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

    if total < 0:
        raise ValueError("Calculated total cannot be negative")

    if not isinstance(payment_details, dict):
        raise ValueError("payment_details must be a dictionary")

    required_payment_fields = ("method",)
    missing_fields = [field for field in required_payment_fields if not payment_details.get(field)]
    if missing_fields:
        raise ValueError(f"Missing payment details: {', '.join(missing_fields)}")

    payment_result = _charge_payment(total, payment_details)

    return {
        "status": "success" if payment_result["approved"] else "failed",
        "user_role": role,
        "discount_percentage": int(discount_rate * 100),
        "subtotal": float(subtotal),
        "discount_amount": float(discount_amount),
        "total_charged": float(total),
        "currency": payment_result.get("currency", "USD"),
        "items": [
            {
                "name": item["name"],
                "quantity": item["quantity"],
                "unit_price": float(item["unit_price"]),
                "line_total": float(item["line_total"]),
            }
            for item in normalized_items
        ],
        "payment": payment_result,
    }


def _charge_payment(amount: Decimal, payment_details: Dict[str, Any]) -> Dict[str, Any]:
    currency = payment_details.get("currency", "USD")
    approved = amount >= Decimal("0.00")

    return {
        "approved": approved,
        "transaction_id": payment_details.get("transaction_id") or "txn_mock_001",
        "method": payment_details.get("method"),
        "currency": currency,
        "amount": float(amount.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)),
    }